#include <bits/stdc++.h>
using namespace std;
int n,a[31],root[31][31];
long long dp[31][31];
void dfs(int l,int r){
	printf("%d ",root[l][r]);
	if(root[l][r]>l)
		dfs(l,root[l][r]-1);
	if(root[l][r]<r)
		dfs(root[l][r]+1,r);
}
int main(){
    scanf("%d",&n);
    for(int i=1;i<=n;i++){
    	scanf("%d",&a[i]);
    	dp[i][i]=a[i],root[i][i]=i;
    }
    for(int len=2;len<=n;len++)
    	for(int l=1;l+len-1<=n;l++){
    		int r=l+len-1;
    		for(int k=l;k<=r;k++)
    			if(dp[l][r]<(k>l?dp[l][k-1]:1)*(k<r?dp[k+1][r]:1)+a[k])
    				dp[l][r]=(k>l?dp[l][k-1]:1)*(k<r?dp[k+1][r]:1)+a[k],root[l][r]=k;
		}
	printf("%lld\n",dp[1][n]);
	dfs(1,n);
    return 0;
}
